suppressPackageStartupMessages(library(leaflet))

pick_path &lt;- function(paths) {
  for (p in paths) if (file.exists(p)) return(p)
  ""
}

flows_path &lt;- pick_path(c(
  "../../data/derived/faf_top_od_flows.csv",
  "../data/derived/faf_top_od_flows.csv",
  "data/derived/faf_top_od_flows.csv"
))
zones_path &lt;- pick_path(c(
  "../../data/derived/faf_zone_centroids.csv",
  "../data/derived/faf_zone_centroids.csv",
  "data/derived/faf_zone_centroids.csv"
))

if (!nzchar(flows_path) || !nzchar(zones_path)) {
  cat("&lt;p&gt;&lt;em&gt;Flow map data not yet generated. Run &lt;code&gt;tools/derive_ui_artifacts.R&lt;/code&gt; before rendering.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}

flows &lt;- if (nzchar(flows_path)) utils::read.csv(flows_path, stringsAsFactors = FALSE) else data.frame()
zones &lt;- if (nzchar(zones_path)) utils::read.csv(zones_path, stringsAsFactors = FALSE) else data.frame()

if (nrow(flows) == 0 || nrow(zones) == 0) {
  cat("&lt;p&gt;&lt;em&gt;Flow map data not yet generated. Run &lt;code&gt;tools/derive_ui_artifacts.R&lt;/code&gt; before rendering.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}

required_flows &lt;- c("origin_id", "dest_id", "tons", "ton_miles", "distance_miles", "commodity_group", "scenario_id")
required_zones &lt;- c("zone_id", "name", "lat", "lon")
missing_flows &lt;- setdiff(required_flows, names(flows))
missing_zones &lt;- setdiff(required_zones, names(zones))
if (length(missing_flows) &gt; 0) stop("faf_top_od_flows.csv missing required columns: ", paste(missing_flows, collapse = ", "))
if (length(missing_zones) &gt; 0) stop("faf_zone_centroids.csv missing required columns: ", paste(missing_zones, collapse = ", "))

zones$zone_id &lt;- as.character(zones$zone_id)
flows$origin_id &lt;- as.character(flows$origin_id)
flows$dest_id &lt;- as.character(flows$dest_id)

orig &lt;- zones[match(flows$origin_id, zones$zone_id), c("zone_id", "name", "lat", "lon")]
dest &lt;- zones[match(flows$dest_id, zones$zone_id), c("zone_id", "name", "lat", "lon")]
names(orig) &lt;- c("origin_id_ref", "origin_name", "lat1", "lon1")
names(dest) &lt;- c("dest_id_ref", "dest_name", "lat2", "lon2")
edges &lt;- cbind(flows, orig, dest)
for (nm in c("lat1", "lon1", "lat2", "lon2")) edges[[nm]] &lt;- suppressWarnings(as.numeric(edges[[nm]]))
edges &lt;- edges[is.finite(edges$lat1) & is.finite(edges$lon1) & is.finite(edges$lat2) & is.finite(edges$lon2), , drop = FALSE]

if (nrow(edges) == 0) {
  cat("&lt;p&gt;&lt;em&gt;No mappable edges found in UI artifacts.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}

rank_desc &lt;- function(x) rank(-x, ties.method = "first")
edges$rank_tons &lt;- ave(edges$tons, edges$scenario_id, FUN = rank_desc)
edges$rank_tmiles &lt;- ave(edges$ton_miles, edges$scenario_id, FUN = rank_desc)
edges$w &lt;- 1 + 6 * (edges$tons / max(edges$tons, na.rm = TRUE))
edges$class_name &lt;- paste0(
  "flow-edge ",
  "scen-", gsub("[^A-Za-z0-9]", "-", toupper(edges$scenario_id)), " ",
  "rt-", edges$rank_tons, " ",
  "rm-", edges$rank_tmiles
)
pal &lt;- colorFactor(c("#1b9e77", "#d95f02"), domain = unique(edges$scenario_id))

cat(
  "&lt;div style='display:flex; gap:16px; align-items:center; margin-bottom:10px;'&gt;",
  "&lt;label&gt;Top N &lt;select id='flow-topn'&gt;&lt;option&gt;10&lt;/option&gt;&lt;option&gt;25&lt;/option&gt;&lt;option selected&gt;50&lt;/option&gt;&lt;/select&gt;&lt;/label&gt;",
  "&lt;label&gt;Weight &lt;select id='flow-weight'&gt;&lt;option value='tons' selected&gt;tons&lt;/option&gt;&lt;option value='ton_miles'&gt;ton_miles&lt;/option&gt;&lt;/select&gt;&lt;/label&gt;",
  "&lt;label&gt;Scenario &lt;select id='flow-scenario'&gt;&lt;option value='ALL' selected&gt;ALL&lt;/option&gt;",
  paste(sprintf("&lt;option value='%s'&gt;%s&lt;/option&gt;", unique(edges$scenario_id), unique(edges$scenario_id)), collapse = ""),
  "&lt;/select&gt;&lt;/label&gt;",
  "&lt;/div&gt;",
  sep = ""
)

&lt;div style='display:flex; gap:16px; align-items:center; margin-bottom:10px;'&gt;&lt;label&gt;Top N &lt;select id='flow-topn'&gt;&lt;option&gt;10&lt;/option&gt;&lt;option&gt;25&lt;/option&gt;&lt;option selected&gt;50&lt;/option&gt;&lt;/select&gt;&lt;/label&gt;&lt;label&gt;Weight &lt;select id='flow-weight'&gt;&lt;option value='tons' selected&gt;tons&lt;/option&gt;&lt;option value='ton_miles'&gt;ton_miles&lt;/option&gt;&lt;/select&gt;&lt;/label&gt;&lt;label&gt;Scenario &lt;select id='flow-scenario'&gt;&lt;option value='ALL' selected&gt;ALL&lt;/option&gt;&lt;option value='CENTRALIZED'&gt;CENTRALIZED&lt;/option&gt;&lt;option value='REGIONALIZED'&gt;REGIONALIZED&lt;/option&gt;&lt;/select&gt;&lt;/label&gt;&lt;/div&gt;

map &lt;- leaflet() |&gt;
  addProviderTiles("OpenStreetMap.Mapnik")

for (i in seq_len(nrow(edges))) {
  e &lt;- edges[i, , drop = FALSE]
  popup_txt &lt;- sprintf(
    "&lt;b&gt;%s → %s&lt;/b&gt;&lt;br/&gt;Scenario: %s&lt;br/&gt;Tons: %.2f&lt;br/&gt;Ton-miles: %.2f&lt;br/&gt;Distance: %.1f mi",
    e$origin_name, e$dest_name, e$scenario_id, e$tons, e$ton_miles, e$distance_miles
  )
  map &lt;- map |&gt;
    addPolylines(
      lng = c(e$lon1, e$lon2),
      lat = c(e$lat1, e$lat2),
      color = pal(e$scenario_id),
      weight = e$w,
      opacity = 0.55,
      options = pathOptions(className = e$class_name),
      popup = popup_txt
    )
}

map &lt;- map |&gt;
  addLegend("bottomright", pal = pal, values = unique(edges$scenario_id), title = "Scenario", opacity = 1) |&gt;
  htmlwidgets::onRender(
    "function(el, x) {
      function applyFilters() {
        var topN = parseInt(document.getElementById('flow-topn').value, 10);
        var metric = document.getElementById('flow-weight').value;
        var scen = document.getElementById('flow-scenario').value;
        var paths = el.querySelectorAll('.flow-edge');
        paths.forEach(function(p) {
          // Avoid regex/backslash escaping pitfalls by using DOMTokenList.
          // Fallback to attribute split for older SVG implementations.
          var classes = p.classList ? Array.from(p.classList) : (p.getAttribute('class') || '').trim().split(' ').filter(Boolean);
          var rank = null;
          var scenarioToken = null;
          classes.forEach(function(c) {
            if (c.indexOf('rt-') === 0 && metric === 'tons') rank = parseInt(c.slice(3), 10);
            if (c.indexOf('rm-') === 0 && metric === 'ton_miles') rank = parseInt(c.slice(3), 10);
            if (c.indexOf('scen-') === 0) scenarioToken = c.replace('scen-', '');
          });
          var keepScenario = (scen === 'ALL') || ((scenarioToken || '').toUpperCase() === scen.toUpperCase());
          var keepRank = (rank !== null && rank &lt;= topN);
          var keep = keepScenario && keepRank;
          p.style.opacity = keep ? '0.62' : '0';
          p.style.pointerEvents = keep ? 'auto' : 'none';
        });
      }
      ['flow-topn','flow-weight','flow-scenario'].forEach(function(id) {
        var node = document.getElementById(id);
        if (node) node.addEventListener('change', applyFilters);
      });
      applyFilters();
    }"
  )

map

pick_path &lt;- function(paths) {
  for (p in paths) if (file.exists(p)) return(p)
  ""
}

summary_path &lt;- pick_path(c(
  "../../data/derived/scenario_summary.csv",
  "../data/derived/scenario_summary.csv",
  "data/derived/scenario_summary.csv"
))

if (!nzchar(summary_path)) {
  summary_path &lt;- pick_path(c(
    "../../outputs/aggregate/results_summary.csv",
    "../outputs/aggregate/results_summary.csv",
    "outputs/aggregate/results_summary.csv"
  ))
}

if (!nzchar(summary_path)) {
  cat("&lt;p&gt;&lt;em&gt;Scenario summary not yet generated. Run &lt;code&gt;Rscript tools/derive_ui_artifacts.R&lt;/code&gt; (or generate &lt;code&gt;outputs/aggregate/results_summary.csv&lt;/code&gt;).&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}

df &lt;- utils::read.csv(summary_path, stringsAsFactors = FALSE)
if (!("scenario_id" %in% names(df))) df$scenario_id &lt;- "AGGREGATE"
if (nrow(df) == 0) {
  cat("&lt;p&gt;&lt;em&gt;Scenario summary is empty.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}
if (!("metric" %in% names(df))) {
  cat("&lt;p&gt;&lt;em&gt;Scenario summary is missing required column &lt;code&gt;metric&lt;/code&gt;. Regenerate artifacts via &lt;code&gt;Rscript tools/derive_ui_artifacts.R&lt;/code&gt;.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}
metric_vals &lt;- trimws(as.character(df$metric))
if (all(!nzchar(metric_vals))) {
  cat("&lt;p&gt;&lt;em&gt;Scenario summary has an empty/invalid &lt;code&gt;metric&lt;/code&gt; column. Regenerate artifacts via &lt;code&gt;Rscript tools/derive_ui_artifacts.R&lt;/code&gt;.&lt;/em&gt;&lt;/p&gt;")
  knitr::knit_exit()
}
if (!("powertrain" %in% names(df))) df$powertrain &lt;- "unknown"
if (!("trailer_type" %in% names(df))) df$trailer_type &lt;- "unknown"
if (!("variant_id" %in% names(df))) df$variant_id &lt;- df$scenario_id

for (nm in c("mean", "var", "p05", "p50", "p95")) {
  if (!(nm %in% names(df))) df[[nm]] &lt;- NA_real_
}
df &lt;- df[order(df$scenario_id, df$powertrain, df$trailer_type, df$metric), c("scenario_id", "variant_id", "powertrain", "trailer_type", "metric", "mean", "var", "p05", "p50", "p95"), drop = FALSE]

scenario_vals &lt;- unique(df$scenario_id)
power_vals &lt;- unique(df$powertrain)
trailer_vals &lt;- unique(df$trailer_type)
scenario_options &lt;- paste(sprintf("&lt;option value='%s'&gt;%s&lt;/option&gt;", scenario_vals, scenario_vals), collapse = "")
power_options &lt;- paste(sprintf("&lt;option value='%s'&gt;%s&lt;/option&gt;", power_vals, power_vals), collapse = "")
trailer_options &lt;- paste(sprintf("&lt;option value='%s'&gt;%s&lt;/option&gt;", trailer_vals, trailer_vals), collapse = "")

row_html &lt;- apply(df, 1, function(r) {
  sprintf(
    "&lt;tr data-scenario='%s' data-power='%s' data-trailer='%s'&gt;&lt;td&gt;%s&lt;/td&gt;&lt;td&gt;%s&lt;/td&gt;&lt;td&gt;%s&lt;/td&gt;&lt;td&gt;%s&lt;/td&gt;&lt;td&gt;%.6g&lt;/td&gt;&lt;td&gt;%.6g&lt;/td&gt;&lt;td&gt;%.6g&lt;/td&gt;&lt;td&gt;%.6g&lt;/td&gt;&lt;td&gt;%.6g&lt;/td&gt;&lt;/tr&gt;",
    toupper(r[["scenario_id"]]), toupper(r[["powertrain"]]), toupper(r[["trailer_type"]]),
    r[["scenario_id"]], r[["variant_id"]], r[["powertrain"]], r[["metric"]],
    as.numeric(r[["mean"]]), as.numeric(r[["var"]]),
    as.numeric(r[["p05"]]), as.numeric(r[["p50"]]), as.numeric(r[["p95"]])
  )
})

cat(
  "&lt;div style='display:flex; gap:16px; align-items:center;'&gt;",
  "&lt;label for='scenario-filter'&gt;&lt;b&gt;Scenario:&lt;/b&gt;&lt;/label&gt; ",
  "&lt;select id='scenario-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;", scenario_options, "&lt;/select&gt;",
  "&lt;label for='power-filter'&gt;&lt;b&gt;Powertrain:&lt;/b&gt;&lt;/label&gt; ",
  "&lt;select id='power-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;", power_options, "&lt;/select&gt;",
  "&lt;label for='trailer-filter'&gt;&lt;b&gt;Trailer:&lt;/b&gt;&lt;/label&gt; ",
  "&lt;select id='trailer-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;", trailer_options, "&lt;/select&gt;",
  "&lt;/div&gt;",
  "&lt;table id='scenario-table' class='table table-striped' style='margin-top:12px;'&gt;",
  "&lt;thead&gt;&lt;tr&gt;&lt;th&gt;Scenario&lt;/th&gt;&lt;th&gt;Variant&lt;/th&gt;&lt;th&gt;Powertrain&lt;/th&gt;&lt;th&gt;Metric&lt;/th&gt;&lt;th&gt;Mean&lt;/th&gt;&lt;th&gt;Var&lt;/th&gt;&lt;th&gt;P05&lt;/th&gt;&lt;th&gt;P50&lt;/th&gt;&lt;th&gt;P95&lt;/th&gt;&lt;/tr&gt;&lt;/thead&gt;",
  "&lt;tbody&gt;", paste(row_html, collapse = "\n"), "&lt;/tbody&gt;&lt;/table&gt;",
  "&lt;script&gt;",
  "const sSel=document.getElementById('scenario-filter');",
  "const pSel=document.getElementById('power-filter');",
  "const tSel=document.getElementById('trailer-filter');",
  "const rows=[...document.querySelectorAll('#scenario-table tbody tr')];",
  "function applyFilters(){",
  " const s=sSel.value.toUpperCase(), p=pSel.value.toUpperCase(), t=tSel.value.toUpperCase();",
  " rows.forEach(r=&gt;{",
  "   const keepS=(s==='ALL'||r.dataset.scenario===s);",
  "   const keepP=(p==='ALL'||r.dataset.power===p);",
  "   const keepT=(t==='ALL'||r.dataset.trailer===t);",
  "   r.style.display=(keepS&&keepP&&keepT)?'':'none';",
  " });",
  "}",
  "sSel.addEventListener('change', applyFilters);",
  "pSel.addEventListener('change', applyFilters);",
  "tSel.addEventListener('change', applyFilters);",
  "applyFilters();",
  "&lt;/script&gt;",
  sep = ""
)

&lt;div style='display:flex; gap:16px; align-items:center;'&gt;&lt;label for='scenario-filter'&gt;&lt;b&gt;Scenario:&lt;/b&gt;&lt;/label&gt; &lt;select id='scenario-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;&lt;option value='AGGREGATE'&gt;AGGREGATE&lt;/option&gt;&lt;option value='CENTRALIZED'&gt;CENTRALIZED&lt;/option&gt;&lt;option value='REGIONALIZED'&gt;REGIONALIZED&lt;/option&gt;&lt;/select&gt;&lt;label for='power-filter'&gt;&lt;b&gt;Powertrain:&lt;/b&gt;&lt;/label&gt; &lt;select id='power-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;&lt;option value='NA'&gt;NA&lt;/option&gt;&lt;option value='bev'&gt;bev&lt;/option&gt;&lt;option value='diesel'&gt;diesel&lt;/option&gt;&lt;/select&gt;&lt;label for='trailer-filter'&gt;&lt;b&gt;Trailer:&lt;/b&gt;&lt;/label&gt; &lt;select id='trailer-filter'&gt;&lt;option value='ALL'&gt;ALL&lt;/option&gt;&lt;option value='NA'&gt;NA&lt;/option&gt;&lt;option value='dry_van'&gt;dry_van&lt;/option&gt;&lt;option value='refrigerated'&gt;refrigerated&lt;/option&gt;&lt;/select&gt;&lt;/div&gt;&lt;table id='scenario-table' class='table table-striped' style='margin-top:12px;'&gt;&lt;thead&gt;&lt;tr&gt;&lt;th&gt;Scenario&lt;/th&gt;&lt;th&gt;Variant&lt;/th&gt;&lt;th&gt;Powertrain&lt;/th&gt;&lt;th&gt;Metric&lt;/th&gt;&lt;th&gt;Mean&lt;/th&gt;&lt;th&gt;Var&lt;/th&gt;&lt;th&gt;P05&lt;/th&gt;&lt;th&gt;P50&lt;/th&gt;&lt;th&gt;P95&lt;/th&gt;&lt;/tr&gt;&lt;/thead&gt;&lt;tbody&gt;&lt;tr data-scenario='AGGREGATE' data-power='NA' data-trailer='NA'&gt;&lt;td&gt;AGGREGATE&lt;/td&gt;&lt;td&gt;aggregate&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;1.63909&lt;/td&gt;&lt;td&gt;0.713316&lt;/td&gt;&lt;td&gt;0.345154&lt;/td&gt;&lt;td&gt;1.74594&lt;/td&gt;&lt;td&gt;4.0139&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='AGGREGATE' data-power='NA' data-trailer='NA'&gt;&lt;td&gt;AGGREGATE&lt;/td&gt;&lt;td&gt;aggregate&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;diff_gco2_gt_zero&lt;/td&gt;&lt;td&gt;0.958445&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='AGGREGATE' data-power='NA' data-trailer='NA'&gt;&lt;td&gt;AGGREGATE&lt;/td&gt;&lt;td&gt;aggregate&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;gco2_dry&lt;/td&gt;&lt;td&gt;2.90471&lt;/td&gt;&lt;td&gt;2.01885&lt;/td&gt;&lt;td&gt;0.163914&lt;/td&gt;&lt;td&gt;2.75951&lt;/td&gt;&lt;td&gt;5.91145&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='AGGREGATE' data-power='NA' data-trailer='NA'&gt;&lt;td&gt;AGGREGATE&lt;/td&gt;&lt;td&gt;aggregate&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;gco2_reefer&lt;/td&gt;&lt;td&gt;4.5438&lt;/td&gt;&lt;td&gt;4.96516&lt;/td&gt;&lt;td&gt;1.48947&lt;/td&gt;&lt;td&gt;4.24092&lt;/td&gt;&lt;td&gt;8.76023&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='AGGREGATE' data-power='NA' data-trailer='NA'&gt;&lt;td&gt;AGGREGATE&lt;/td&gt;&lt;td&gt;aggregate&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;ratio&lt;/td&gt;&lt;td&gt;1.56675&lt;/td&gt;&lt;td&gt;0.00937741&lt;/td&gt;&lt;td&gt;1.41187&lt;/td&gt;&lt;td&gt;1.56125&lt;/td&gt;&lt;td&gt;1.73304&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='CENTRALIZED' data-power='BEV' data-trailer='DRY_VAN'&gt;&lt;td&gt;CENTRALIZED&lt;/td&gt;&lt;td&gt;CENTRALIZED_BEV_DRY&lt;/td&gt;&lt;td&gt;bev&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;1.37153&lt;/td&gt;&lt;td&gt;0.503178&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='CENTRALIZED' data-power='BEV' data-trailer='DRY_VAN'&gt;&lt;td&gt;CENTRALIZED&lt;/td&gt;&lt;td&gt;CENTRALIZED_BEV_DRY&lt;/td&gt;&lt;td&gt;bev&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;1.63207&lt;/td&gt;&lt;td&gt;0.707097&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='CENTRALIZED' data-power='BEV' data-trailer='DRY_VAN'&gt;&lt;td&gt;CENTRALIZED&lt;/td&gt;&lt;td&gt;CENTRALIZED_BEV_DRY&lt;/td&gt;&lt;td&gt;bev&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;1.63909&lt;/td&gt;&lt;td&gt;0.713316&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='CENTRALIZED' data-power='BEV' data-trailer='DRY_VAN'&gt;&lt;td&gt;CENTRALIZED&lt;/td&gt;&lt;td&gt;CENTRALIZED_BEV_DRY&lt;/td&gt;&lt;td&gt;bev&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;1.37153&lt;/td&gt;&lt;td&gt;0.503178&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
&lt;tr data-scenario='CENTRALIZED' data-power='BEV' data-trailer='DRY_VAN'&gt;&lt;td&gt;CENTRALIZED&lt;/td&gt;&lt;td&gt;CENTRALIZED_BEV_DRY&lt;/td&gt;&lt;td&gt;bev&lt;/td&gt;&lt;td&gt;diff_gco2&lt;/td&gt;&lt;td&gt;3.10813&lt;/td&gt;&lt;td&gt;2.6365&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;td&gt;NA&lt;/td&gt;&lt;/tr&gt;
